@VisibleForTesting
static byte[] readFully(InputStream is, int numBytes) throws IOException {
    byte[] b = new byte[numBytes];
    int count = 0;
    do {
        int n = is.read(b, count, numBytes - count);
        if (n > 0) {
            count += n;
        } else {
            throw new RuntimeException("unexpected");
        }
    } while (count < numBytes);
    return b;
}

